# Problem: Implement a health check and metrics system for a FastAPI application.
# We need health checkers for components, request/system metrics tracking,
# and sample check functions for database, redis, and disk.
#
# Approach:
# - HealthChecker stores named check functions in a dict, runs them, and
#   determines overall status using worst-status-wins priority.
# - RequestMetrics stores all request records in a list for percentile calcs,
#   plus dicts for aggregation.
# - SystemMetrics tracks uptime from init time and event counters.
# - p95 uses: sort durations, index = ceil(0.95 * n) - 1
#
# Time complexity: O(n log n) for p95 (sorting), O(n) for most summaries
# Space complexity: O(n) where n = number of recorded requests
#
# Key steps:
# 1. Implement ComponentStatus constants and HealthCheck Pydantic model
# 2. Build HealthChecker with register/run_all/run_one
# 3. Build RequestMetrics with record/get_summary/get_endpoint_stats/reset
# 4. Build SystemMetrics with uptime, events, system info
# 5. Implement sample check functions with specified thresholds

import sys
import time
import math
from typing import Callable
from pydantic import BaseModel


class ComponentStatus:
    HEALTHY = 'healthy'
    DEGRADED = 'degraded'
    UNHEALTHY = 'unhealthy'


class HealthCheck(BaseModel):
    name: str
    status: str
    response_time_ms: float | None = None
    details: dict | None = None


class HealthChecker:
    def __init__(self):
        self._checks: dict[str, Callable] = {}

    def register(self, name: str, check_func: Callable) -> None:
        self._checks[name] = check_func

    def run_all(self) -> dict:
        results = {}
        # Priority map: higher number = worse status
        priority = {
            ComponentStatus.HEALTHY: 0,
            ComponentStatus.DEGRADED: 1,
            ComponentStatus.UNHEALTHY: 2,
        }
        worst = ComponentStatus.HEALTHY
        for name, func in self._checks.items():
            check = func()
            results[name] = check.model_dump()
            # Update overall status if this check is worse
            if priority.get(check.status, 0) > priority.get(worst, 0):
                worst = check.status
        return {
            'status': worst,
            'checks': results,
            'timestamp': time.time(),
        }

    def run_one(self, name: str) -> HealthCheck:
        if name not in self._checks:
            raise KeyError(name)
        return self._checks[name]()


class RequestMetrics:
    def __init__(self):
        self._records: list[dict] = []

    def record(self, method: str, path: str, status_code: int, duration_ms: float) -> None:
        self._records.append({
            'method': method,
            'path': path,
            'status_code': status_code,
            'duration_ms': duration_ms,
        })

    def get_summary(self) -> dict:
        total = len(self._records)
        if total == 0:
            return {
                'total_requests': 0,
                'by_method': {},
                'by_status': {},
                'avg_duration_ms': 0.0,
                'p95_duration_ms': 0.0,
                'error_rate': 0.0,
            }
        by_method: dict[str, int] = {}
        by_status: dict[int, int] = {}
        durations: list[float] = []
        errors = 0
        for r in self._records:
            by_method[r['method']] = by_method.get(r['method'], 0) + 1
            by_status[r['status_code']] = by_status.get(r['status_code'], 0) + 1
            durations.append(r['duration_ms'])
            if r['status_code'] >= 400:  # 4xx and 5xx are errors
                errors += 1
        durations.sort()
        # p95: index = ceil(0.95 * n) - 1
        p95_index = math.ceil(0.95 * total) - 1
        return {
            'total_requests': total,
            'by_method': by_method,
            'by_status': by_status,
            'avg_duration_ms': sum(durations) / total,
            'p95_duration_ms': durations[p95_index],
            'error_rate': errors / total,
        }

    def get_endpoint_stats(self) -> list[dict]:
        # Group by (method, path)
        endpoints: dict[tuple[str, str], list[float]] = {}
        for r in self._records:
            key = (r['method'], r['path'])
            if key not in endpoints:
                endpoints[key] = []
            endpoints[key].append(r['duration_ms'])
        stats = []
        for (method, path), times in endpoints.items():
            stats.append({
                'method': method,
                'path': path,
                'count': len(times),
                'avg_ms': sum(times) / len(times),
                'max_ms': max(times),
            })
        # Sort by count descending
        stats.sort(key=lambda x: x['count'], reverse=True)
        return stats

    def reset(self) -> None:
        self._records.clear()


class SystemMetrics:
    def __init__(self):
        self.start_time = time.time()
        self._events: dict[str, int] = {}

    def get_uptime_seconds(self) -> float:
        return time.time() - self.start_time

    def record_event(self, event_type: str) -> None:
        self._events[event_type] = self._events.get(event_type, 0) + 1

    def get_event_counts(self) -> dict[str, int]:
        return dict(self._events)

    def get_system_info(self) -> dict:
        return {
            'uptime_seconds': self.get_uptime_seconds(),
            'events': self.get_event_counts(),
            'python_version': sys.version,
        }


def check_database(healthy: bool = True) -> HealthCheck:
    if healthy:
        return HealthCheck(
            name='database',
            status=ComponentStatus.HEALTHY,
            response_time_ms=5.0,
        )
    return HealthCheck(
        name='database',
        status=ComponentStatus.UNHEALTHY,
        response_time_ms=5000.0,
        details={'error': 'Connection refused'},
    )


def check_redis(healthy: bool = True, degraded: bool = False) -> HealthCheck:
    if not healthy:
        return HealthCheck(
            name='redis',
            status=ComponentStatus.UNHEALTHY,
            response_time_ms=5000.0,
            details={'error': 'Connection refused'},
        )
    if degraded:
        return HealthCheck(
            name='redis',
            status=ComponentStatus.DEGRADED,
            response_time_ms=500.0,
            details={'warning': 'High latency'},
        )
    return HealthCheck(
        name='redis',
        status=ComponentStatus.HEALTHY,
        response_time_ms=2.0,
    )


def check_disk(usage_percent: float = 50.0) -> HealthCheck:
    # < 80% healthy, < 95% degraded, >= 95% unhealthy
    if usage_percent < 80.0:
        status = ComponentStatus.HEALTHY
    elif usage_percent < 95.0:
        status = ComponentStatus.DEGRADED
    else:
        status = ComponentStatus.UNHEALTHY
    return HealthCheck(
        name='disk',
        status=status,
        details={'usage_percent': usage_percent},
    )
